var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"알고 있을 텐데? 난 원래 세계에서도 길바닥 시궁쥐 출신이었다고.","JPN":"知ってんだろ？　オレは元の世界でも底辺のドブネズミの生まれだってこと。","ENG":"I thought you knew already? I was a street kid back in my original world.","TWN":"你應該知道吧？我在我原本的世界也是隻過街老鼠。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"인생에 행복한 일 따위는 전혀 없었어. 그저 하루하루를 살아남으려고 버틸 뿐이었지.","JPN":"生きていて幸せだなんて全然感じたことなかった。ただ毎日を生き延びるために耐えていただけだ。","ENG":"There was nothing happy about life. It was more about getting by, day after day.","TWN":"我人生中從未發生過任何幸福的事，只是過一天算一天而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"그런 내 뭘 믿고…… 평생을 함께한다는 거야?","JPN":"そんなオレのどこを見て……一生一緒にいるなんて言うのさ？","ENG":"But what do you see in me that... you want to spend the rest of your days with me?","TWN":"那老闆是看中我什麼……為什麼要跟我簽一輩子的約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"혹시 사장도 나를 속이려는 거야?","JPN":"まさか社長もオレを騙そうとしてるのか？","ENG":"Wait, are you trying to scam me too, Boss?","TWN":"你該不會是想騙我吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"동정하지 마, 시궁쥐도 시궁쥐 나름대로의 프라이드라는 게 있으니까.","JPN":"同情なんてするなよ。ドブネズミだってドブネズミなりのプライドってもんがあるんだ。","ENG":"I don't need your sympathy. Even sewer rats have dignity.","TWN":"我不需要你的同情，過街老鼠也是有自尊的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 그냥 야구 상대가 되어 달라고?","JPN":"何だって？　ただ野球の相手になってくれ？","ENG":"What? You just want me to be your baseball buddy?","TWN":"蛤？你只是想當我的練球對象？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"회사에는…… 야구 할 줄 아는 사람이 없어……?","JPN":"会社には……野球ができる人がいない……？","ENG":"Is there... no one at the company who knows how to play baseball...?","TWN":"在公司裡……沒有會打棒球的人……？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"……푸흡!","JPN":"……ぷっ！","ENG":"...Pfft!","TWN":"……噗哈！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"푸하하하하하! 그래! 언제 그 얘길 하나 했다!","JPN":"ぷははははは！　そうか！　いつその話を持ちだすのかと思ってたんだ！","ENG":"Ha ha ha ha ha! Sure! I was wondering when you'd ask!","TWN":"噗哈哈哈哈哈！我還想說你什麼時候才會提呢！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"좋아! 이 몸의 깔끔한 타격폼을 보게 된 이상 그런 반응을 보이는 게 당연하거든!","JPN":"うん！　オレのすっきりとしたバッティングフォームを見てしまったからには、その反応は当然だよな！","ENG":"Okay! It's only natural to react that way after seeing my perfect batting form!","TWN":"沒問題！看到我俐落的打擊姿勢後，有這種反應也是正常的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"1번 타자든, 4번 타자든 나한테 맡겨만 달라고!","JPN":"1番打者でも4番打者でも、どんと来いってんだ！","ENG":"Be it the leadoff hitter or the cleanup hitter, leave it to me!","TWN":"不管是第一棒還是第四棒，全都交給我吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"하핫! 마음에 들었어, 사장 그 계약서인지 뭔지 내놔 봐. 깔끔하게 해치워주지!","JPN":"ははっ！　気に入ったぜ、社長。その契約書だか何だか、出しな。ささっと片づけてやるよ！","ENG":"Haha! I like you, Boss. Hand over that contract or whatever it is. I'll sign it!","TWN":"哈哈！我欣賞你，老闆！把那個契約書還什麼的拿來！來辦妥這件事吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"아, 맞다. 그런데 말이지.","JPN":"あ、そうだ。ところでさ。","ENG":"Oh, right. Just one thing.","TWN":"喔，不過，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"나 글자 못 읽는데…… 사장이 글자 좀 알려주면 안 돼?","JPN":"オレ、字が読めないんだけど……社長が教えてくれない？","ENG":"I don't know how to read... So could you teach me, Boss?","TWN":"我看不懂字……老闆可以讀給我聽嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};